import base64
import ctypes
import os
from tkinter import messagebox

import customtkinter as ctk
import psutil

# --- 资源区 (Base64) ---
RUNNER_EXE_B64 = ""
HOOK_DLL_B64 = ""
MHOOK_DLL_B64=""""""

TEMP_PATH = os.environ.get("TEMP")
RUNNER_PATH = os.path.join(TEMP_PATH, "NTDHookRunner.exe")
DLL_PATH = os.path.join(TEMP_PATH, "NTDHooks.dll")
CONFIG_FILE = os.path.join(TEMP_PATH, "NTDHooksConfig")


class WarningWindow(ctk.CTkToplevel):
    """强化警告样式的声明弹窗"""

    def __init__(self, parent):
        super().__init__(parent)
        self.title("须知")
        self.geometry("450x400")

        # 居中显示
        self.attributes("-topmost", True)
        self.after(100, self.lift)
        self.protocol("WM_DELETE_WINDOW", self.on_close)

        # 1. 顶部警告横条 (使用 Frame 模拟 Header)
        header_frame = ctk.CTkFrame(self, fg_color="#332B00", height=60, corner_radius=0)
        header_frame.pack(fill="x", side="top")

        ctk.CTkLabel(header_frame, text="⚠️ SYSTEM WARNING",
                     font=("Impact", 24),
                     text_color="#FFCC00").pack(pady=10)

        # 2. 中间主体内容
        content_frame = ctk.CTkFrame(self, fg_color="transparent")
        content_frame.pack(expand=True, fill="both", padx=20, pady=10)

        # 这里的字体加粗增强视觉冲击力
        msg_title = ctk.CTkLabel(content_frame, text="此功能尚不稳定，可能导致不可预知的后果",
                                 font=("Microsoft YaHei", 13, "bold"),
                                 text_color="#FF4C4C")
        msg_title.pack(pady=(5, 10))

        # 3. 文本框样式：增加深色背景和金色边框
        msg = ctk.CTkTextbox(content_frame, width=420, height=220,
                             font=("Microsoft YaHei", 12),
                             border_width=2,
                             border_color="#554400",  # 深金色边框
                             fg_color="#1A1A1A")  # 深黑底色

        # 插入内容
        warning_text = (
            "此功能尚不稳定，开启后会自动在极域运行远程命令和杀掉进程时弹框确认，"
            "可能出现各种失败如极域崩溃，继续吗？\n\n"
            "如果因此被掉线导致您当场寄掉，这个banchen(nigger)可是不负责任的呢awa\n\n"
            "🛠️ 已实现的拦截项：\n"
            " • 禁止黑屏广播反复切换焦点\n"
            " • 拦截极域远程运行/关机\n"
            " • 拦截极域杀掉进程\n"
            " • 拦截极域关闭窗口\n"
            " • 禁止极域广播置顶"
        )
        msg.insert("0.0", warning_text)
        msg.configure(state="disabled")
        msg.pack(pady=5)

        # 4. 底部操作按钮：使用醒目的黄色按钮
        self.btn = ctk.CTkButton(self, text="行了，我已知晓",
                                 font=("Microsoft YaHei", 14, "bold"),
                                 fg_color="#FFCC00",
                                 text_color="black",
                                 hover_color="#CCAA00",
                                 height=40,
                                 command=self.on_close)
        self.btn.pack(pady=(0, 20))

        self.grab_set()

    def on_close(self):
        self.grab_release()
        self.withdraw()  # 先隐藏
        self.update_idletasks()  # 刷新待处理任务
        self.destroy()


class NTDManager(ctk.CTk):
    def __init__(self):
        super().__init__()

        # --- 核心 UI 设置 ---
        self.title("")
        self.geometry("180x200")
        ctk.set_appearance_mode("dark")

        # --- 1. 隐藏主窗口 ---
        self.withdraw()

        # --- 2. 释放资源与配置 ---
        self.release_files()
        self.ensure_config_exists()

        # --- 3. 构建主界面组件 ---
        self.label = ctk.CTkLabel(self, text="极域 Hook", font=("Arial", 22, "bold"))
        self.label.pack(pady=20)

        # minhook_button = ctk.CTkButton(
        #     self,
        #     text="🛠️ 部署环境",
        #     font=ctk.CTkFont(size=16, weight="bold"),
        #     fg_color="#2E778D",
        #     hover_color="#1E2B6C",
        #     text_color="#FFFFFF",
        #     border_width=2,
        #     border_color="#3D94B3",
        #     corner_radius=12,
        #     height=11,
        #     width=100,
        #     # 使用 lambda 在后台线程中调用保存并打开的函数，避免界面卡死
        #     command=lambda: threading.Thread(
        #         target=lambda: self.MinHook(),
        #         daemon=True
        #     ).start()
        # )
        # minhook_button.pack(pady=15, padx=10)

        self.main_switch = ctk.CTkSwitch(self, text="注入极域钩子", command=self.on_inject_toggle)
        self.main_switch.pack(pady=10)

        self.slider_label = ctk.CTkLabel(self, text="拦截模式: 弹出警告 (0)", font=("Microsoft YaHei", 12))
        self.slider_label.pack(pady=(20, 0))

        self.mode_slider = ctk.CTkSlider(self, from_=0, to=1, number_of_steps=1, command=self.update_config)
        self.mode_slider.set(0)
        self.mode_slider.pack(pady=10, padx=50)

        self.status_label = ctk.CTkLabel(self, text="状态: 就绪", text_color="gray")
        self.status_label.pack(side="bottom", pady=10)

        # --- 4. 启动声明逻辑 ---
        self.after(10, self.start_with_warning)

    def start_with_warning(self):
        """显示弹窗并阻塞，直到关闭后显示主界面"""
        warn = WarningWindow(self)
        self.wait_window(warn)  # 关键：这里会阻塞，直到 warn 窗口销毁
        self.deiconify()  # 显示主界面
        self.check_loop()  # 开始状态监测

    def release_files(self):
        try:
            for path, data in [(RUNNER_PATH, RUNNER_EXE_B64), (DLL_PATH, HOOK_DLL_B64)]:
                if len(data) > 10:
                    with open(path, "wb") as f:
                        f.write(base64.b64decode(data))
        except:
            pass

    def ensure_config_exists(self):
        if not os.path.exists(CONFIG_FILE):
            try:
                with open(CONFIG_FILE, "w") as f:
                    f.write("0 0")
            except:
                pass

    def update_config(self, value):
        val = int(value)
        mode_text = "直接放行 (1)" if val == 1 else "弹出警告 (0)"
        self.slider_label.configure(text=f"拦截模式: {mode_text}")
        try:
            with open(CONFIG_FILE, "w") as f:
                f.write(f"{val} {val}")
        except Exception as e:
            self.status_label.configure(text=f"状态: 配置更新失败 {e}", text_color="red")

    def is_injected(self):
        try:
            # 必须请求 pid
            for proc in psutil.process_iter(['name', 'pid']):
                try:
                    name = proc.info.get('name')
                    if name and name.lower() == "studentmain.exe":
                        # 必须管理员权限运行 Python 才能看到 memory_maps
                        for module in proc.memory_maps():
                            if "NTDHooks.dll" in module.path:
                                return True, proc.info['pid']
                except (psutil.AccessDenied, psutil.NoSuchProcess):
                    continue  # 遇到权限问题跳过，继续找
            return False, None
        except Exception as e:
            return False, None

    def check_loop(self):
        injected, pid = self.is_injected()
        if injected:
            self.status_label.configure(text=f"状态: 钩子已激活 (PID: {pid})", text_color="#4CAF50")
            self.main_switch.select()
            self.main_switch.configure(state="disabled")
        else:
            self.status_label.configure(text="状态: 等待注入", text_color="gray")
            self.main_switch.deselect()
            self.main_switch.configure(state="normal")
        self.after(2000, self.check_loop)

    def on_inject_toggle(self):
        if self.main_switch.get() == 1:
            target_name = "studentmain.exe"
            # 查找进程 PID
            pid = next((p.info['pid'] for p in psutil.process_iter(['name', 'pid'])
                        if p.info.get('name') and p.info['name'].lower() == target_name), None)

            if pid:
                # 1. 更新配置文件
                self.update_config(self.mode_slider.get())

                # 2. 准备参数
                params = f'--pid={pid}'

                try:
                    # 打印调试信息
                    print(f"正在请求管理员权限启动: {RUNNER_PATH} --pid={pid}")

                    # 3. 正确调用 Shell32 库中的 ShellExecuteW
                    # 使用 windll.shell32 而不是直接在类定义中引用
                    ret = ctypes.windll.shell32.ShellExecuteW(
                        None,  # 父窗口句柄
                        "runas",  # 请求提升管理员权限 (UAC)
                        str(RUNNER_PATH),  # 注入器程序的完整路径
                        params,  # 命令行参数
                        None,  # 工作目录
                        1  # SW_SHOWNORMAL (显示窗口)
                    )

                    # 返回值大于 32 表示成功启动
                    if ret > 32:
                        print(f"管理员权限指令已发送 (PID: {pid})")
                    else:
                        # 如果返回 5 依然说明用户在 UAC 弹窗点选了“取消”
                        messagebox.showerror("权限错误", f"操作被拒绝或失败 (错误码: {ret})")
                        self.main_switch.deselect()

                except Exception as e:
                    messagebox.showerror("代码错误", f"调用 ShellExecute 时发生异常: {e}")
                    self.main_switch.deselect()
            else:
                messagebox.showwarning("提示", f"未找到进程 {target_name}")
                self.main_switch.deselect()

    def release_minhook_to_target(self,process_name="StudentMain.exe", b64_data=""):
        """
        定位目标进程目录并释放 MinHook.x86.dll
        :param process_name: 目标进程名
        :param b64_data: DLL 的 Base64 编码数据
        :return: (bool, message) 成功状态及提示信息
        """
        if not b64_data:
            return False, "未提供 Base64 数据"

        target_path = None

        # 1. 寻找进程并获取路径
        for proc in psutil.process_iter(['name', 'exe']):
            try:
                if proc.info['name'].lower() == process_name.lower():
                    target_path = os.path.dirname(proc.info['exe'])
                    break
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                continue

        if not target_path:
            return False, f"未找到正在运行的 {process_name}"

        # 2. 构造 DLL 完整路径
        dll_full_path = os.path.join(target_path, "MinHook.x86.dll")

        # 3. 尝试释放文件
        try:
            # 如果文件已存在且被占用，这里会报错，所以先尝试写入
            with open(dll_full_path, "wb") as f:
                f.write(base64.b64decode(b64_data))
            return True, f"成功释放到: {dll_full_path}"
        except PermissionError:
            return False, "权限不足！请以管理员身份运行此脚本。"
        except Exception as e:
            return False, f"写入失败: {str(e)}"

    def MinHook(self):
        success, msg = self.release_minhook_to_target("StudentMain.exe", MHOOK_DLL_B64)
        print(msg)


def open_hook():
    app = NTDManager()
    app.MinHook()
    app.mainloop()


if __name__ == "__main__":
    open_hook()